using Microsoft.Extensions.AI;
using OpenAI;
using System.ComponentModel;
using System.Text.Json;

Console.WriteLine("Research Agent Starting...");

var topic = args.Length > 0 ? string.Join(" ", args) : "recent advances in quantum computing";
Console.WriteLine($"Researching topic: {topic}\n");

// Configure the AI client
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");

var client = new OpenAIClient(openAiKey)
    .GetChatClient("gpt-4o")
    .AsIChatClient();

// Register tools
var researchTools = new ResearchTools();
var chatOptions = new ChatOptions
{
    Tools = [
        AIFunctionFactory.Create(researchTools.SearchWeb),
        AIFunctionFactory.Create(researchTools.TakeNote),
        AIFunctionFactory.Create(researchTools.GetNotes),
    ]
};

// Build conversation with system prompt
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to research a given topic thoroughly.

        Instructions:
        1. Use the SearchWeb tool multiple times with different queries to gather information.
        2. Use the TakeNote tool to record important findings as you go.
        3. After gathering enough information, use GetNotes to review what you've collected.
        4. Finally, provide a comprehensive summary of your research findings.

        Be thorough but concise. Search for different aspects of the topic.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}")
};

// Agent loop - keep calling the model until it stops requesting tools
Console.WriteLine("Agent is researching...\n");

const int maxIterations = 15;
int iteration = 0;

while (iteration++ < maxIterations)
{
    var response = await client.GetResponseAsync(messages, chatOptions);

    // Add the assistant response to the conversation
    messages.Add(new ChatMessage(ChatRole.Assistant, response.Message.Contents));

    // Check if there are tool calls to process
    var toolCalls = response.Message.Contents.OfType<FunctionCallContent>().ToList();
    if (toolCalls.Count == 0)
    {
        // No more tool calls - agent is done
        var finalText = string.Join("", response.Message.Contents.OfType<TextContent>().Select(t => t.Text));
        Console.WriteLine("═══════════════════════════════════════════");
        Console.WriteLine("RESEARCH SUMMARY");
        Console.WriteLine("═══════════════════════════════════════════");
        Console.WriteLine(finalText);
        break;
    }

    // Process each tool call
    var toolResults = new List<AIContent>();
    foreach (var toolCall in toolCalls)
    {
        var result = await toolCall.InvokeAsync(chatOptions.Tools.OfType<AIFunction>());
        Console.WriteLine($"  [Tool] {toolCall.Name}({FormatArgs(toolCall.Arguments)})");
        toolResults.Add(new FunctionResultContent(toolCall.CallId, result));
    }

    messages.Add(new ChatMessage(ChatRole.Tool, toolResults));
}

if (iteration >= maxIterations)
{
    Console.WriteLine("\n[Agent reached maximum iterations]");
}

Console.WriteLine($"\nNotes collected: {researchTools.NoteCount}");

static string FormatArgs(IDictionary<string, object?>? args) =>
    args is null ? "" : string.Join(", ", args.Select(kv => $"{kv.Key}: \"{kv.Value}\""));

// === Tool Definitions ===

public class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _httpClient = new();

    public int NoteCount => _notes.Count;

    [Description("Search the web for information on a query. Returns search results as text.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var response = await _httpClient.GetStringAsync(url);
            var doc = JsonDocument.Parse(response);
            var root = doc.RootElement;

            var results = new List<string>();

            // Get abstract if available
            if (root.TryGetProperty("Abstract", out var abs) && abs.GetString() is { Length: > 0 } abstractText)
            {
                results.Add($"Summary: {abstractText}");
            }

            // Get related topics
            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) && text.GetString() is { Length: > 0 } topicText)
                    {
                        results.Add($"- {topicText}");
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n", results)
                : $"No detailed results found for '{query}'. Try a different search query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Take a note to record an important finding during research.")]
    public string TakeNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all notes taken so far during this research session.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes taken yet.";

        return string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

